import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Appraisal.css";

const Appraisal = () => {
  const [appraisals, setAppraisals] = useState([]);
  const navigate = useNavigate();

  // Load from localStorage on page load
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("appraisals")) || [];

    // If nothing exists, load sample data once
    if (stored.length === 0) {
      const sample = [
        {
          id: 1,
          employeeName: "Rahul R",
          department: "IT",
          period: "Jan 2024 - Dec 2024",
          rating: 4.5,
          status: "Approved",
        },
        {
          id: 2,
          employeeName: "Sneha K",
          department: "HR",
          period: "Jan 2024 - Dec 2024",
          rating: 4.2,
          status: "Pending",
        },
        {
          id: 3,
          employeeName: "David M",
          department: "Finance",
          period: "Jan 2024 - Dec 2024",
          rating: 3.8,
          status: "Rejected",
        },
      ];

      localStorage.setItem("appraisals", JSON.stringify(sample));
      setAppraisals(sample);
    } else {
      setAppraisals(stored);
    }
  }, []);

  // Delete Appraisal
  const handleDelete = (id) => {
    if (!window.confirm("Are you sure you want to delete this appraisal?")) return;

    const filtered = appraisals.filter((a) => a.id !== id);
    setAppraisals(filtered);
    localStorage.setItem("appraisals", JSON.stringify(filtered));
  };

  // Navigate to Add Page
  const handleAdd = () => {
    navigate("/dashboard/appraisal/add");
  };

  // Navigate to View Page (future)
  const handleView = (id) => {
    navigate(`/dashboard/appraisal/view/${id}`);
  };

  // Navigate to Edit Page (future)
  const handleEdit = (id) => {
    navigate(`/dashboard/appraisal/edit/${id}`);
  };

  return (
    <div className="appraisal-container">

      <h2 className="appraisal-title">Employee Appraisals</h2>

      <div className="appraisal-header">
        <button className="add-btn" onClick={handleAdd}>
          Add New Appraisal
        </button>
      </div>

      <table className="appraisal-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Employee Name</th>
            <th>Department</th>
            <th>Review Period</th>
            <th>Rating</th>
            <th>Status</th>
            <th style={{ textAlign: "center" }}>Actions</th>
          </tr>
        </thead>

        <tbody>
          {appraisals.length === 0 ? (
            <tr>
              <td colSpan="7" style={{ textAlign: "center" }}>
                No Appraisals Found
              </td>
            </tr>
          ) : (
            appraisals.map((item, index) => (
              <tr key={item.id}>
                <td>{index + 1}</td>
                <td>{item.employeeName}</td>
                <td>{item.department}</td>
                <td>{item.period}</td>
                <td>{item.rating}</td>

                <td>
                  <span className={`status-badge ${item.status.toLowerCase()}`}>
                    {item.status}
                  </span>
                </td>

                <td className="action-col">
                  <button className="view-btn" onClick={() => handleView(item.id)}>
                    View
                  </button>

                  <button className="edit-btn" onClick={() => handleEdit(item.id)}>
                    Edit
                  </button>

                  <button
                    className="delete-btn"
                    onClick={() => handleDelete(item.id)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default Appraisal;
